const text = $fromAI('text', 'The text or URL to encode in the QR code');
const format = $fromAI('format', 'Output format: png or svg', 'string', 'png');
const size = $fromAI('size', 'Size in pixels between 100 and 1000', 'number', 300);

const response = await fetch('https://www.acrewity.com/api/services/execute', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer YOUR_ACREWITY_API_KEY'
  },
  body: JSON.stringify({
    service: 'qr_code_generator',
    operation: 'generate_qr',
    parameters: { text, format, size: Number(size) }
  })
});

const data = await response.json();
return JSON.stringify(data);

